import React, { useState } from 'react';
import { sendMessage } from '../services/api';
import MessageBubble from './MessageBubble';
import './ChatWindow.css';

function ChatWindow() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = { sender: 'user', text: input };
    const history = messages.map(m => [m.sender, m.text]);

    try {
      const response = await sendMessage(input, history);
      const botMsg = { sender: 'bot', text: response.reply };

      setMessages([...messages, userMsg, botMsg]);
    } catch {
      const errorMsg = { sender: 'bot', text: 'Error: backend unreachable.' };
      setMessages([...messages, userMsg, errorMsg]);
    }

    setInput('');
  };

  return (
    <div className="chat-window">
      <div className="messages">
        {messages.map((msg, i) => (
          <MessageBubble key={i} text={msg.text} sender={msg.sender} />
        ))}
      </div>
      <div className="input-area">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Type a message..."
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
}

export default ChatWindow;
